import json
import re
import pandas as pd

# Load business data
with open(locals()['var_function-call-155350076985845784'], 'r') as f:
    business_list = json.load(f)

# Load review data
with open(locals()['var_function-call-5223981229576103887'], 'r') as f:
    review_list = json.load(f)

valid_states = set([
    'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 
    'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 
    'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY', 'DC'
])

business_wifi_map = {}
wifi_businesses = []

for b in business_list:
    bid = b.get('business_id')
    attrs = b.get('attributes')
    desc = b.get('description', '')

    # Check WiFi
    has_wifi = False
    if isinstance(attrs, dict):
        wifi = attrs.get('WiFi')
        if wifi:
            w_str = str(wifi).lower()
            if 'free' in w_str or 'paid' in w_str:
                has_wifi = True

    if has_wifi:
        # Extract State
        # Find all 2-letter uppercase words
        matches = re.findall(r'\b([A-Z]{2})\b', desc)
        found_state = None
        for m in matches:
            if m in valid_states:
                found_state = m
                break # Take the first valid state found

        if found_state:
            business_wifi_map[bid] = found_state
            wifi_businesses.append(bid)

# Aggregate ratings
business_ratings = {}

for r in review_list:
    ref = r.get('business_ref')
    if not ref: continue
    bid = ref.replace("businessref_", "businessid_")

    if bid in business_wifi_map:
        if bid not in business_ratings:
            business_ratings[bid] = []
        try:
            val = float(r['rating'])
            business_ratings[bid].append(val)
        except:
            pass

# Compute stats
state_stats = {}

for bid in wifi_businesses:
    if bid in business_ratings and len(business_ratings[bid]) > 0:
        ratings = business_ratings[bid]
        avg_rating = sum(ratings) / len(ratings)

        state = business_wifi_map[bid]
        if state not in state_stats:
            state_stats[state] = {'count': 0, 'sum_avg_rating': 0}

        state_stats[state]['count'] += 1
        state_stats[state]['sum_avg_rating'] += avg_rating

results = []
for state, stats in state_stats.items():
    avg_of_avgs = stats['sum_avg_rating'] / stats['count']
    results.append({
        'state': state,
        'wifi_business_count': stats['count'],
        'average_rating': avg_of_avgs
    })

df = pd.DataFrame(results)

if not df.empty:
    df = df.sort_values(by=['wifi_business_count', 'average_rating'], ascending=[False, False])
    print("__RESULT__:")
    print(df.to_json(orient='records'))
else:
    print("__RESULT__:")
    print(json.dumps([]))

